using System;using System.IO;using ICSharpCode.WpfDesign;namespace BgCommon.UI.Designer.Export{    /// <summary>    /// 导出格式    /// </summary>    public enum ExportFormat    {        /// <summary>        /// 可执行文件        /// </summary>        Executable,        /// <summary>        /// HTML/CSS        /// </summary>        HtmlCss,        /// <summary>        /// XML        /// </summary>        Xml,        /// <summary>        /// JSON        /// </summary>        Json    }        /// <summary>    /// 导出管理器    /// </summary>    public class ExportManager    {        private readonly DesignContext _context;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public ExportManager(DesignContext context)        {            _context = context;        }                /// <summary>        /// 导出设计        /// </summary>        /// <param name="path">导出路径</param>        /// <param name="format">导出格式</param>        /// <returns>是否导出成功</returns>        public bool Export(string path, ExportFormat format)        {            try            {                switch (format)                {                    case ExportFormat.Executable:                        return ExportAsExecutable(path);                    case ExportFormat.HtmlCss:                        return ExportAsHtmlCss(path);                    case ExportFormat.Xml:                        return ExportAsXml(path);                    case ExportFormat.Json:                        return ExportAsJson(path);                    default:                        return false;                }            }            catch (Exception ex)            {                Console.WriteLine($"导出失败: {ex.Message}");                return false;            }        }                /// <summary>        /// 导出为可执行文件        /// </summary>        /// <param name="path">导出路径</param>        /// <returns>是否导出成功</returns>        private bool ExportAsExecutable(string path)        {            // 这里可以实现导出为可执行文件的逻辑            // 例如，创建一个包含设计内容的WPF应用程序            Console.WriteLine($"导出为可执行文件: {path}");            return true;        }                /// <summary>        /// 导出为HTML/CSS        /// </summary>        /// <param name="path">导出路径</param>        /// <returns>是否导出成功</returns>        private bool ExportAsHtmlCss(string path)        {            // 这里可以实现导出为HTML/CSS的逻辑            // 例如，将WPF元素转换为HTML和CSS            Console.WriteLine($"导出为HTML/CSS: {path}");            return true;        }                /// <summary>        /// 导出为XML        /// </summary>        /// <param name="path">导出路径</param>        /// <returns>是否导出成功</returns>        private bool ExportAsXml(string path)        {            try            {                using (var writer = System.Xml.XmlWriter.Create(path, new System.Xml.XmlWriterSettings { Indent = true }))                {                    _context.Save(writer);                }                return true;            }            catch (Exception ex)            {                Console.WriteLine($"导出为XML失败: {ex.Message}");                return false;            }        }                /// <summary>        /// 导出为JSON        /// </summary>        /// <param name="path">导出路径</param>        /// <returns>是否导出成功</returns>        private bool ExportAsJson(string path)        {            try            {                // 首先保存为XML字符串                using (var stringWriter = new StringWriter())                using (var xmlWriter = System.Xml.XmlWriter.Create(stringWriter, new System.Xml.XmlWriterSettings { Indent = true }))                {                    _context.Save(xmlWriter);                    var xmlContent = stringWriter.ToString();                                        // 将XML转换为JSON                    var xmlDoc = new System.Xml.XmlDocument();                    xmlDoc.LoadXml(xmlContent);                    var jsonContent = Newtonsoft.Json.JsonConvert.SerializeXmlNode(xmlDoc, Newtonsoft.Json.Formatting.Indented);                                        // 写入文件                    File.WriteAllText(path, jsonContent);                    return true;                }            }            catch (Exception ex)            {                Console.WriteLine($"导出为JSON失败: {ex.Message}");                return false;            }        }    }}